
const PHASE_TESTING = {
  name:"Phase 20 · Testing Strategy",id:"test",icon:"🧪",phase:"Testing",color:"#fb923c",
  sizes:["small","medium","large","hyper"],
  short:"Unit → integration → load → chaos → continuous verification — the portfolio that makes deploys boring",
  detail:{
    what:"Testing strategy is the portfolio of verification activities that gives your team confidence to deploy to production many times a day without fear. It's not just 'writing tests' — it's a deliberate, layered defense system where each type of test catches a different class of bug at a different cost and speed. The portfolio includes: (1) Unit tests — verify individual functions/classes in isolation, run in milliseconds, catch logic bugs, form the base of the pyramid. (2) Integration tests — verify that components work together (service + database, service + cache, service + downstream API), run in seconds, catch wiring bugs. (3) Contract tests — verify that the API contract between services hasn't broken, without full integration — the most cost-effective test type for microservices. (4) Load tests — verify that the system handles projected (and 2–10× projected) traffic without breaking SLOs, catch capacity/concurrency bugs. (5) Chaos engineering — verify that the system survives real-world failures (instance death, network partition, disk full, dependency timeout), catch resilience bugs. (6) Production verification — canary deploys, synthetic monitoring, and progressive rollout that continuously verify the system in the environment that matters most. The traditional 'test pyramid' (many unit tests, fewer integration, fewest E2E) is correct for monoliths but misleading for distributed systems: in microservices, the bugs that cause outages are almost always at the boundaries between services (wrong data format, unexpected null, changed API response shape), and unit tests don't catch those. Contract tests and integration tests are the workhorses of distributed system reliability.",
    why:"Test strategy directly determines two things: how fast you can ship (deploy frequency) and how often shipping causes pain (change failure rate). DORA research — the largest study of software delivery performance, spanning 32,000+ teams over 8 years — shows that elite teams deploy on demand (multiple times per day), have <15% change failure rate, and recover from incidents in <1 hour. Low-performing teams deploy monthly, have 31–45% failure rate, and take over a week to recover. The difference isn't talent — it's test strategy. Elite teams have automated test suites that catch bugs before production, progressive delivery that limits blast radius, and monitoring that detects problems in seconds. Counter-intuitively, teams that deploy more often have fewer outages because: each change is small (easier to debug), the deploy process is well-practiced (fewer manual mistakes), and problems are detected quickly (less time to accumulate damage). Testing isn't about preventing all bugs — it's about making bugs cheap, fast to detect, and easy to fix. A bug caught by a unit test costs 1 minute. Caught by an integration test, 10 minutes. Caught in staging, 1 hour. Caught in production by monitoring, 1 day. Caught by a customer support ticket, 1 week. Caught by a compliance audit, 1 quarter. Every layer of testing shifts bugs left (earlier in the pipeline) where they're cheaper to fix.",
    numbers:"DORA elite tier benchmarks (2023): deploy frequency >1/day per service, lead time for changes <1 day, change failure rate <15%, time to restore service <1 hour. Test execution time targets: unit tests <5 minutes total (run on every commit), integration tests <15 minutes (run on every PR), load tests <30 minutes (run weekly or pre-release), chaos experiments 1–4 hours (run monthly). Code coverage: 80% line coverage is a reasonable target for critical paths — but coverage is a vanity metric if tests are shallow. 50% meaningful coverage (tests that assert behavior, not just execute code) beats 95% shallow coverage. Contract test ROI: catches 80%+ of service-boundary bugs at 10× less cost than E2E tests. The formula: if your E2E test suite takes 45 minutes and is flaky 20% of the time, and contract tests take 2 minutes with <1% flake rate, switching saves each developer 30+ minutes per day in CI wait time."
  },
  tradeoffs:[
    {axis:"Coverage vs Speed",left:"More comprehensive test suite: catches more bugs but CI takes 30+ minutes — developers context-switch, flow is broken, PRs pile up",right:"Leaner test suite: CI finishes in 5 minutes but more bugs reach production — faster feedback loop but higher change failure rate",pos:0.5},
    {axis:"Pre-prod vs In-prod testing",left:"Extensive staging tests: safe, catches bugs before users see them, but staging never perfectly matches production (different data, different traffic patterns, different configuration)",right:"Progressive delivery in prod (canary, feature flags): tests against real traffic and real data — the ultimate reality check — but real users are exposed to bugs (mitigated by small blast radius)",pos:0.5},
    {axis:"Deterministic vs Realistic",left:"Mocked tests: fast, deterministic, repeatable — but they test your mocks, not your system. Mock drift (mock behaves differently than the real service) is a common source of false confidence",right:"Full integration tests: test the real system, but slow, flaky (network, timing), hard to run in CI. Reserve for critical paths.",pos:0.5}
  ],
  pitfalls:[
    {name:"Test pyramid applied literally to microservices",desc:"The test pyramid (many unit tests, some integration, few E2E) was designed for monoliths where most logic is internal. In a microservices system, most bugs live at service boundaries: service A sends a field name 'user_name', service B expects 'username'. A thousand unit tests in each service won't catch this — only contract or integration tests will. For microservices, reshape the portfolio: healthy unit tests (for business logic), extensive contract tests (for every service boundary), targeted integration tests (for critical cross-service flows), and minimal E2E tests (smoke tests for the most critical user journeys only). This is sometimes called the 'test honeycomb' — thickest in the middle (contract/integration) rather than the bottom (unit)."},
    {name:"Flaky tests that erode trust",desc:"A test that fails 5% of the time due to timing, network, or test-order dependencies is worse than no test. Why? Because developers learn to ignore test failures ('oh, that one's always flaky'). When a real failure appears in the same suite, it's invisible — lost among the noise. The fix: quarantine flaky tests immediately. Move them to a separate CI job that runs but doesn't block. Fix the root cause within 1 week or delete the test. Track flake rate as a team metric (Google tracks this rigorously). A test with >1% flake rate must be fixed or removed."},
    {name:"Staging that doesn't match production",desc:"Your staging environment is 1 instance with a 100MB test database. Production is 50 instances across 3 AZs with a 500GB database, connection pooling, caching, and CDN. A bug that only manifests under concurrent load, high connection count, or large dataset size will never appear in staging. Staging must match production's topology even if scaled down: same services, same networking (VPC peering, DNS), same configuration management, same database engine (not H2 in staging and Postgres in prod — a shockingly common anti-pattern). Use production data snapshots (anonymized/synthesized) for realistic data volume. The mantra: staging should be a miniature production, not a different system."},
    {name:"E2E tests as the primary safety net",desc:"A comprehensive E2E test suite that exercises every user journey through a browser sounds like thorough testing. In practice: it takes 45 minutes to run, is flaky 30% of the time (Selenium/Playwright timing issues, dynamic content, network delays), blocks deploys constantly with false negatives, and gives no useful signal about where a failure is. It's the most expensive type of test to write, maintain, and run. Limit E2E to 5–10 critical smoke tests (login, checkout, core user journey). Use contract tests for service boundaries and integration tests for component interactions — they run 10× faster with 10× less flake."},
    {name:"No load testing before launch",desc:"Your system works perfectly at 10 RPS in staging. Launch day brings 1000 RPS and your database connection pool is exhausted in 30 seconds — your app returns 500 errors to your very first real users. Load testing before launch is non-negotiable: test at 1×, 2×, 5×, and 10× your projected peak. Find the 'knee' (the inflection point where latency goes from linear to exponential increase) and provision to stay below 60% of it. This takes 1 day of effort and prevents the most humiliating failure mode: crashing on your biggest day."},
    {name:"Feature flags that never get cleaned up",desc:"You shipped a feature behind a flag 18 months ago. The flag is still in the code, surrounded by conditional logic that nobody understands. Is it safe to remove? Which code path is the 'real' one? The flag config is in LaunchDarkly but no one remembers what it does. Set an expiration date on every feature flag at creation time (typically 30–90 days after full rollout). Add a CI check that fails if a flag exists past its expiration. Treat feature flag cleanup like tech debt — schedule it explicitly."}
  ],
  examples:[
    {name:"Google's testing culture — the Testing on the Toilet initiative",desc:"Google famously posts 'Testing on the Toilet' (TotT) — short lessons about testing printed and posted in bathroom stalls across Google offices. This cultural investment matters: Google's engineering culture treats testing as a first-class engineering skill, not a chore. Google's test infrastructure (Blaze, now open-sourced as Bazel) caches test results by input hash — if nothing changed, the test doesn't re-run. This enables 100,000+ tests to run in minutes. The cultural lesson: testing speed and testing culture are force multipliers. If tests are slow, developers skip them. If testing is culturally valued, developers write better tests."},
    {name:"Shopify's testing strategy at scale",desc:"Shopify runs one of the world's largest Rails monoliths with thousands of developers. Their CI runs ~150,000 tests. To keep CI fast, they: (1) parallelize across many machines (CI on beefy cloud instances), (2) run only tests affected by the changed files (test selection based on dependency graph), (3) quarantine flaky tests into a separate pipeline, (4) track test health metrics per test file (flake rate, execution time, failure-to-fix time). They maintain a 'CI health team' dedicated to keeping the test suite fast and reliable. The lesson: at scale, test infrastructure is a product that needs a team."},
    {name:"Netflix's progressive delivery — from canary to full production",desc:"When Netflix deploys a new version, it follows a rigorous progressive delivery pipeline: (1) Automated tests pass in CI. (2) Deploy to a single canary instance serving ~0.1% of traffic. (3) Automated analysis compares canary metrics (latency, error rate, CPU) against baseline for 30 minutes. (4) If canary is healthy: expand to 5% → 25% → 100% over several hours. (5) If any metric degrades: automatic rollback within seconds. The key insight: no amount of pre-production testing can substitute for real production traffic. Progressive delivery makes production testing safe by limiting blast radius. Netflix's deployment tool (Spinnaker, which they open-sourced) is the industry standard for this pattern."},
    {name:"Knight Capital — $440M loss from missing tests",desc:"On August 1, 2012, Knight Capital deployed new trading software. Due to a deployment error, old code was left running on one of eight servers. The old code interpreted a new configuration flag differently and began buying high, selling low — executing millions of unintended trades. In 30 minutes, Knight Capital lost $440 million and essentially ceased to exist. The root causes: (1) No automated deployment verification (the old code on one server wasn't detected). (2) No anomaly monitoring (the system was losing millions per minute and no alert fired for 30 minutes). (3) No integration test that validated deployment consistency across servers. Any single test — deployment verification, anomaly detection, or integration check — would have caught this within seconds. Knight Capital is the most expensive testing failure in history."}
  ],
  levelUp:[
    {from:"small",to:"medium",trigger:">5 engineers or >1 production incident caused by a regression that a test would have caught — this is the point where 'we'll test manually' stops working",action:"Build a three-layer test foundation: (1) Integration tests on critical paths — identify your 5 most important user journeys (signup, login, core action, payment, data export) and write automated integration tests for each that hit a real database (use docker-compose to spin up Postgres + Redis in CI). These tests run in <5 minutes and catch the bugs that actually cause outages. (2) Contract tests between services — if you have >2 services, use Pact (open source, supports 10+ languages) to define API contracts: the consumer defines what it expects, the producer verifies it doesn't break those expectations. Pact runs in seconds and prevents the #1 microservices bug (breaking API changes deployed independently). (3) CI gates on test pass — configure GitHub Actions (free for public repos, 2,000 min/month free for private) or CircleCI ($30/month for 5 users) to block PR merge if tests fail. Make 'all tests pass' a merge requirement. Total setup time: 1–2 weeks. Technologies: Jest (JavaScript testing, fast parallel execution), pytest (Python, excellent fixtures), RSpec (Ruby, expressive DSL), Pact (contract testing, multi-language), GitHub Actions (CI/CD, generous free tier), docker-compose (spin up dependencies for integration tests)."},
    {from:"medium",to:"large",trigger:">50 services or any cascading failure incident — the point where service-boundary failures dominate and you need systematic resilience verification",action:"Add three advanced capabilities: (1) Load tests in CI — use k6 (open source, JavaScript-based load testing, runs in CI) to define performance benchmarks: 'this endpoint must handle 1000 RPS at p99 <200ms.' Run against a staging environment weekly and before major releases. Start by identifying your 3 hottest endpoints and writing load scenarios for each — this takes 1 day and prevents launch-day disasters. k6 Cloud ($99/month) adds distributed load generation and trend analysis. Alternative: Locust (Python-based, excellent for complex user flows). (2) Monthly chaos engineering — use Gremlin ($80/host/month, managed chaos platform with a controlled UI — safer for getting started) or AWS FIS (native AWS, free for the tool, you pay for the resources). Start with the simplest experiment: kill one instance of your most critical service and verify it recovers within your SLO (load balancer removes it, health check detects failure, new instance starts). Do this in staging first, then production. Schedule it monthly — if the calendar entry doesn't exist, chaos engineering doesn't happen. (3) Canary deploys with auto-rollback — configure your deployment tool (ArgoCD for Kubernetes, Spinnaker, or AWS CodeDeploy) to deploy new versions to 1% of traffic first, compare error rate and latency against baseline for 10 minutes, and automatically roll back if metrics degrade. This makes every production deploy a safe experiment. Total setup time: 2–4 weeks across the three capabilities."},
    {from:"large",to:"hyper",trigger:">500 services or zero-tolerance reliability requirements — at this scale, pre-production testing is necessary but insufficient; production is the test environment that matters",action:"Implement three advanced practices: (1) Continuous chaos in production — not monthly drills, but always-on low-rate failure injection. Configure your service mesh (Istio/Envoy) to inject 100ms of latency into 0.01% of requests between service A and service B, permanently. This ensures your circuit breakers and timeouts are always exercised, not just during drills. Expand to instance kills (Chaos Monkey-style, always running during business hours), disk slowness injection, and network partition simulation. Budget: dedicated chaos engineering team (2–3 engineers). (2) Formal verification of critical algorithms — for consensus protocols, distributed locks, and financial calculations, use TLA+ (Leslie Lamport's specification language) to mathematically prove correctness. Amazon uses TLA+ for DynamoDB, S3, and EBS. Azure uses it for Cosmos DB. This is a specialized skill — hire or train 1–2 engineers, start with your most critical invariant (e.g., 'money is never created or destroyed in a transfer'). (3) Synthetic monitoring from every PoP — deploy synthetic transaction monitors (Datadog Synthetic Tests, Checkly, or custom) that continuously execute critical user journeys (login, search, purchase) from every geographic region. These run every 1–5 minutes and alert on failure or latency degradation. Unlike real-user monitoring, synthetic tests catch issues before users are affected (e.g., a misconfigured firewall rule that blocks traffic from Asia). Budget: Datadog Synthetic at $12/test/month, Checkly at $7/check/month. Combined with production chaos and progressive delivery, this creates a system where bugs are caught within seconds of deployment, limited to <1% of users, and rolled back automatically."}
  ],
  sizes_cfg:{
    small:{range:"<5 engineers, <5 services, deploying a few times per week",rec:"Focus on integration tests for critical paths over exhaustive unit tests. Write integration tests for your 5 most important user flows — tests that exercise the full stack (HTTP request → application logic → database → response). Use docker-compose to run Postgres and Redis in CI so tests hit real infrastructure, not mocks. Keep the total suite under 5 minutes. Add a basic smoke test that runs after each deploy (hit /health, hit the homepage, verify 200). Use GitHub Actions for CI (free tier is generous: 2,000 minutes/month for private repos). Technology comparison: GitHub Actions (free, YAML-based, excellent marketplace of pre-built actions) vs CircleCI (faster build caching, $30/month for 5 users) vs GitLab CI (built into GitLab, good if you're already on GitLab). For test frameworks: Jest (JavaScript, fast parallel execution, built-in coverage), pytest (Python, powerful fixtures, excellent plugin ecosystem), RSpec (Ruby, most expressive test DSL in any language), Go testing (built into the language, fast, no framework needed).",tools:["GitHub Actions","Jest","pytest","RSpec","docker-compose"]},
    medium:{range:"5–50 engineers, 5–50 services, deploying daily",rec:"Expand the test portfolio: unit tests for business logic (fast, developers run locally), integration tests for critical flows (in CI, with real dependencies), contract tests between services (Pact or schema registry), and pre-launch load tests. CI should run in <15 minutes — if it's slower, parallelize (split tests across multiple runners) and cache dependencies aggressively. Add a staging environment that mirrors production topology (same services, same networking, different scale). Run load tests against staging before every major release using k6 (write once, run in CI or standalone). Set up basic production monitoring that alerts if error rate >1% in the 15 minutes after a deploy — this is your cheapest 'production test.' Technology comparison: Pact (consumer-driven contracts, tests that the producer's API meets the consumer's expectations, supports HTTP and message contracts, 10+ languages — the industry standard) vs schema registry (Buf for Protobuf, Confluent Schema Registry for Avro — validates that schema evolution doesn't break consumers, but doesn't test behavior). Use Pact for HTTP APIs, schema registry for event schemas — they complement each other. For load testing: k6 (JavaScript-based, open source, excellent CLI, integrates with Grafana — best for developers) vs Locust (Python-based, excellent for complex user flows with state, good UI — best for QA teams) vs Artillery (YAML config, simplest to get started — best for quick checks).",tools:["Pact","k6","Locust","schema registry","staging environment"]},
    large:{range:"50–500 engineers, 50–500 services, deploying many times per day",rec:"The full portfolio: unit (fast, developer-local), contract (every service boundary), integration (critical cross-service flows), load (weekly, against staging), chaos (monthly, graduating to production), and progressive delivery (every deploy). Contract tests are now mandatory on every service boundary — no service can deploy if it breaks a consumer's contract. CI pipeline: tests run in parallel across many runners (Buildkite scales well here, ~$0.06/minute for cloud runners), with test selection (only run tests affected by changed code — Facebook's approach). Chaos engineering: monthly experiments in staging, graduating to quarterly in production with tight blast radius. Tools like Gremlin provide guardrails (automatic abort if error rate exceeds threshold). Progressive delivery: every production deploy goes through canary (1% for 10 min) → regional rollout (one region for 30 min) → global. Automated rollback triggers: error rate increase >0.5%, latency p99 increase >20%, or any custom business metric degradation. Technology comparison: Spinnaker (Netflix-built deployment tool, excellent canary analysis with Kayenta, powerful but complex to operate) vs ArgoCD (Kubernetes-native GitOps, simpler, excellent for K8s-only shops) vs Flagger (Kubernetes progressive delivery, integrates with Istio/Envoy for traffic shifting, simpler than Spinnaker). For chaos: Gremlin ($80/host/month, managed, safest for getting started, good UI) vs Chaos Mesh (open source, Kubernetes-native, free, more hands-on) vs AWS FIS (native AWS, free tool, integrates with CloudWatch for abort conditions) vs Litmus (open source, Kubernetes-focused, CNCF project).",tools:["Buildkite","Spinnaker/ArgoCD","Gremlin/Chaos Mesh","Pact at scale","k6 Cloud"]},
    hyper:{range:">500 engineers, >500 services, zero-tolerance reliability",rec:"Testing is a platform capability, not a per-team activity. The platform team provides: (1) A CI/CD pipeline that every service inherits (standard test stages, standard canary analysis, standard rollback triggers). (2) A chaos engineering platform that continuously injects low-rate failures in production. (3) Synthetic monitoring from every PoP. (4) Formal verification tools (TLA+) and training for critical-path teams. (5) A test health dashboard showing flake rate, coverage, and CI time per service — teams with degrading test health get automated nudges. At this scale, E2E tests are almost entirely replaced by production verification: canary analysis, synthetic monitoring, and real-user monitoring (RUM) provide faster, more realistic signal than any staging environment. The staging environment exists for load testing and destructive experiments, not for functional verification. Technology comparison: TLA+ (formal verification language — proves that your algorithm is correct for ALL possible inputs, not just the ones you tested. Amazon has used it to find bugs in DynamoDB that no amount of testing would catch. Learning curve: 2–4 weeks for an experienced engineer to become productive, 3–6 months to become expert) vs Alloy (simpler formal modeling language, good for data model invariants) vs property-based testing (QuickCheck/Hypothesis — generates random inputs to find edge cases, less rigorous than TLA+ but much easier to adopt). For synthetic monitoring: Datadog Synthetic ($12/test/month, browser tests and API tests from global locations) vs Checkly ($7/check/month, modern alternative with Playwright-based browser tests) vs Grafana Synthetic (newer, integrates with Grafana stack).",tools:["TLA+","Datadog Synthetic","Checkly","custom CI/CD platform","continuous chaos"]}
  },
  children:[
    {name:"Load & Capacity",id:"test-load",icon:"📊",phase:"Testing",color:"#fb923c",
     sizes:["medium","large","hyper"],short:"k6/Locust → distributed → game days — find the breaking point before your users do",
     detail:{
       what:"Load and capacity testing verifies that your system handles the projected traffic — and 2–10× projected traffic — without breaking SLOs. It answers the most important operational question: 'Where does this system break?' There are four types: (1) Load test — sustained traffic at projected peak for 30–60 minutes. Verifies steady-state behavior under expected load. (2) Stress test — ramp traffic beyond projected peak (2×, 5×, 10×) to find the breaking point ('knee'). Tells you your capacity ceiling. (3) Spike test — sudden burst from baseline to 10× in seconds. Verifies autoscaling speed and load shedding behavior. (4) Soak test — sustained moderate load for 8–24 hours. Finds memory leaks, connection pool exhaustion, log disk fill, and other slow-burn failures that don't appear in short tests. The output of load testing is not 'pass/fail' — it's a capacity profile: 'this system handles 5,000 RPS at p99 <200ms, degrades gracefully to 8,000 RPS at p99 <500ms, and falls over at 12,000 RPS.' This profile drives capacity planning: provision to operate at 60% of the knee, with autoscaling up to 80%.",
       why:"Capacity bugs are unique: they cannot be found by any other type of testing. A function that works correctly at 1 RPS can deadlock at 1,000 RPS due to lock contention. A database query that returns in 5ms with 100K rows takes 5 seconds with 10M rows. A connection pool of 10 is fine at 50 RPS but exhausted at 500 RPS when a downstream service adds 100ms of latency. These bugs are invisible in unit tests, integration tests, and even manual testing — they only appear under load. Discovering them in production is the most expensive and humiliating failure mode: your biggest day (launch, Black Friday, viral moment) becomes your worst day. Load testing before launch is not optional — it's the difference between a celebration and a disaster. Regular load testing (weekly or before each release) is also essential because capacity changes over time: new features add queries, data grows, and what worked at 1M rows may not work at 10M.",
       numbers:"Test at these multiples of your projected peak: 1× (verify SLOs hold at expected load), 2× (verify the system handles a busy day), 5× (find the stress point — where does degradation begin?), 10× (find the breaking point — what happens when the system is overwhelmed? Does it degrade gracefully with load shedding, or crash catastrophically?). Key metric: the 'knee' — the inflection point where latency goes from linear increase to exponential. Provision infrastructure to operate at 60% of the knee, giving 40% headroom for unexpected spikes. Load test duration: 30 minutes minimum for load tests (need to see steady-state, not just cold-start behavior), 8–24 hours for soak tests. Test data: use production-like key distribution (not a single user_id — that hits cache every time; distribute across realistic cardinality). Tools can generate 10K–100K+ RPS from a single machine (k6, Vegeta) or millions with distributed mode (k6 Cloud, Locust workers, Gatling Enterprise)."
     },
     tradeoffs:[{axis:"Realism vs Cost",left:"Test with real production data (anonymized): accurate traffic patterns, realistic cache behavior, true database performance — but requires data sanitization pipeline and production-like infrastructure",right:"Synthetic load scripts: cheap, fast to set up, but may miss production-specific patterns (hot keys, data skew, realistic session behavior) — use production key distributions to improve realism",pos:0.5},{axis:"Frequency vs Engineering time",left:"Load test on every deploy: catches regressions immediately but requires fast, automated, reliable load test infrastructure",right:"Load test quarterly: catches major issues but regressions accumulate between tests — monthly is a good middle ground",pos:0.5}],
     sizes_cfg:{
       medium:{range:"Single-machine load generation, manual analysis",rec:"Write k6 scripts (JavaScript) for your 3 hottest endpoints. k6 is the best tool for developers: write tests in JavaScript, run from CLI, built-in metrics and thresholds, integrates with Grafana. Define pass/fail thresholds: `http_req_duration{p99}<200` (p99 latency under 200ms). Run before every major release against staging. Use production-like data: don't test with 100 rows — load a sanitized copy of production data or generate realistic volumes. Monitor not just the API, but the database (CPU, connections, slow query log), cache (hit rate, memory), and downstream services during the test. Technologies: k6 (open source, JavaScript, excellent CLI output, threshold-based pass/fail, exports to Grafana — the best developer experience for load testing), Locust (Python, excellent for complex multi-step user flows, has a web UI for real-time monitoring), Artillery (YAML config, simplest to get started, good for quick smoke-load tests), Vegeta (Go, HTTP-only, excellent for constant-rate testing and latency histograms — great for API benchmarking).",tools:["k6","Locust","Artillery","Vegeta"]},
       large:{range:"Distributed load generation, automated analysis, traffic replay",rec:"Distributed load testing: k6 Cloud ($99/month, runs tests from multiple global regions, provides trend analysis across test runs — invaluable for tracking performance regressions over time), or self-hosted distributed Locust (deploy Locust workers on multiple machines for combined 100K+ RPS generation). Traffic replay: capture production traffic (GoReplay records and replays HTTP traffic, zero application changes needed) and replay at 10× speed against staging — the most realistic test possible because it uses actual request patterns, key distributions, and timing. Run load tests weekly against staging (automated, in CI, with alerting on regression). Integrate load test results into your deployment pipeline: if performance has degraded >10% from the previous release, flag the deploy for human review. Technologies: k6 Cloud (managed distributed load testing, global regions, trend analysis — best for teams that want results without infrastructure management), GoReplay (open source, captures and replays live traffic — best for realistic replay testing), Gatling Enterprise (Scala-based, excellent for enterprise with detailed reporting, $$$), Tsung (Erlang-based, extremely efficient for generating high RPS, steeper learning curve).",tools:["k6 Cloud","Locust distributed","GoReplay","Gatling"]},
       hyper:{range:"Continuous load in production (shadow traffic), game days",rec:"Shadow traffic: mirror a percentage of production traffic to a staging or canary environment for continuous load testing against real request patterns. Envoy proxy supports traffic mirroring natively (mirror 1–10% of traffic to a shadow cluster without affecting users). This is the ultimate realistic load test — it uses actual production traffic. Game days: scheduled exercises simulating extreme scenarios (Black Friday, viral spike, region failure) with cross-functional participation (engineering + SRE + product + leadership). Run quarterly with increasing intensity. Script the scenario: '10× normal traffic for 2 hours while one AZ is unavailable.' Measure MTTD (time to detect the problem), MTTR (time to resolve), and customer impact. Technologies: Envoy traffic mirroring (free, built into Envoy/Istio — the simplest way to shadow production traffic), custom replay infrastructure (capture Kafka events from production, replay into test environment at any speed), game day playbooks (document scenarios, expected behaviors, escalation procedures — treat them like fire drills).",tools:["Envoy traffic mirroring","custom replay","game day playbooks","shadow clusters"]}
     },
     levelUp:[
       {from:"medium",to:"large",trigger:"Load tests reveal bottlenecks not visible in staging, or production traffic patterns differ significantly from synthetic scripts",action:"Implement traffic replay: deploy GoReplay (open source, single binary, zero code changes) to capture 1 hour of production traffic, then replay it at 1×, 5×, and 10× against staging. This gives you the most realistic load test possible. Set up automated weekly load tests in CI: k6 script → run against staging → compare p99 latency and error rate against baseline → alert on regression. This takes 2–3 days to set up and prevents capacity regressions from accumulating."},
       {from:"large",to:"hyper",trigger:"Staging can't replicate production behavior accurately (different data, different caching, different connection patterns), or you need continuous capacity verification",action:"Implement shadow traffic testing: configure Envoy (via Istio if you're using a service mesh) to mirror 1% of production traffic to a shadow cluster. The shadow cluster processes real requests but doesn't return responses to users — it's a risk-free production load test running continuously. Establish quarterly game days: pick a realistic disaster scenario (major dependency failure + traffic spike), involve the entire engineering org, and measure response. Document findings and remediate gaps. This takes a dedicated SRE/platform team to run but provides confidence that no staging environment can match."}
     ],
     pitfalls:[
       {name:"Single-keyspace load test",desc:"You hammer user_id=1 with 10,000 requests. That user's data is in cache, their row is in the database buffer pool, and every request is a cache hit. Your test shows 0.5ms p99 — amazing! In production, 10,000 different users hit 10,000 different keys, most of which aren't cached. Real p99 is 50ms. Always distribute test load across realistic key cardinality — use a CSV of anonymized production user_ids, or generate UUIDs matching your production distribution."},
       {name:"Testing the API but not the database",desc:"Your load test hammers the HTTP endpoint, which returns quickly because a bug in your test data means every request is a cache hit. The database is idle during the test. In production, 30% of requests are cache misses and hit the DB — which wasn't tested. Load test the full stack: deliberately vary test data to ensure a realistic mix of cache hits and misses. Monitor the database (query/sec, CPU, connection count, replication lag) during the test, not just the API layer."},
       {name:"Load testing without monitoring",desc:"You run a load test but only look at the k6 output. Meanwhile, the database is at 95% CPU, the Redis hit rate dropped to 40%, and replication lag is 30 seconds — all of which would cause cascading failures in production with slightly more traffic. During load tests: monitor every component in real-time (Grafana dashboard with database, cache, queue, and application metrics). The load test output tells you the symptoms; the monitoring tells you the cause."}
     ],
     examples:[
       {name:"Amazon's pre-Prime-Day load testing",desc:"Amazon runs the largest load test in the world before every Prime Day: they simulate 2–3× the projected peak traffic across their entire infrastructure for days. Teams that can't demonstrate their service handles the projected load are blocked from participating in Prime Day features. This multi-week effort involves thousands of engineers and is the reason Prime Day outages have become rare despite traffic growing 30–50% year-over-year."},
       {name:"GitHub's load testing of Actions",desc:"Before major GitHub Actions launches, GitHub replays production traffic at 10× against a canary environment for 48 hours. They discovered multiple scaling bottlenecks (queue backup, connection pool exhaustion, hot partitions) that were invisible at normal traffic levels but would have caused outages at launch."}
     ],
     related:[{id:"req-traffic",label:"Traffic & Scale"},{id:"compute",label:"Compute & Scaling"}],
     children:[]},

    {name:"Chaos Engineering",id:"test-chaos",icon:"🐒",phase:"Testing",color:"#fb923c",
     sizes:["large","hyper"],short:"Inject failures · validate resilience · because hope is not a strategy",
     detail:{
       what:"Chaos engineering is the discipline of deliberately injecting failures into your system — killing instances, partitioning networks, filling disks, slowing dependencies, corrupting data — to verify that your resilience mechanisms (circuit breakers, retries, failover, load shedding) actually work under real conditions. It's based on a simple premise: failures will happen in production (disks fail, networks partition, processes crash, dependencies go down). The only question is whether you've validated your system's response to those failures before they happen naturally, or whether the first real test of your failover is during an actual outage at 3am on a holiday weekend. Chaos engineering answers: 'If X fails, what happens?' — and ensures the answer is 'the system continues operating with minimal user impact' rather than 'we find out the hard way.' The practice was pioneered by Netflix (Chaos Monkey, 2010) out of necessity: running on AWS, where instance failures are routine, they needed confidence that any server could die at any moment without affecting the user experience. Today it's practiced by every major tech company and increasingly by enterprises.",
       why:"Every system has resilience mechanisms — circuit breakers, health checks, auto-scaling, failover databases, redundant services. But how do you know they work? The answer, for most companies, is: you don't, because you've never tested them. Your circuit breaker is configured but has never tripped. Your auto-failover database has a standby that's never been promoted. Your load shedding config has numbers someone picked from a blog post. These mechanisms are theater until proven real. Chaos engineering is proof. It's the difference between 'our docs say we can survive an AZ failure' and 'we survived a real AZ failure last Tuesday during our chaos experiment.' The first time you test your disaster recovery should not be during an actual disaster. The psychological benefit is equally important: teams that practice chaos engineering are calmer during real incidents because they've seen the failure mode before, they know the recovery playbook works, and they've practiced the response. This confidence translates directly to faster MTTR (Mean Time To Recovery).",
       numbers:"Progression: Start in staging weekly with simple experiments (kill one instance, verify recovery). Move to production monthly with blast radius limits (single AZ, single service, single cell). Graduate to continuous low-rate chaos in production (always-on). Measure two things per experiment: MTTD (Mean Time To Detect — how long until your monitoring alerts?) and MTTR (Mean Time To Recover — how long until the system is fully healthy?). Target: MTTD <2 minutes, MTTR <5 minutes for instance-level failures. For region-level failures: MTTD <5 minutes, MTTR <15 minutes. If your MTTD is >10 minutes, your monitoring is broken — fix that before doing more chaos experiments. Cost of chaos engineering: Gremlin managed platform ($80/host/month for 50+ hosts), Chaos Mesh (free, Kubernetes-native), AWS FIS (free tool, you pay for resources used). Cost of NOT doing chaos engineering: finding out your failover doesn't work during a real outage — MTTR measured in hours instead of minutes, revenue loss, customer impact, and an SRE team that's terrified of every deploy."
     },
     tradeoffs:[{axis:"Realism vs Risk",left:"Chaos in production: the most realistic test — uses real traffic, real data, real dependencies — but a chaos experiment gone wrong can cause real user impact. Mitigate with blast radius limits and automatic abort conditions",right:"Chaos in staging: safe, no user impact — but staging doesn't have real traffic patterns, real data volumes, or real timing. Failures that only manifest under production load (e.g., connection pool exhaustion under concurrent retries) won't appear",pos:0.5},{axis:"Frequency vs Cost",left:"Continuous always-on chaos (0.01% failure rate injected permanently): ensures resilience is continuously exercised, catches regressions immediately — but requires mature monitoring and automated abort, and some engineering overhead",right:"Monthly drills: lower overhead, planned and staffed, but resilience regressions can accumulate between tests, and the drills feel artificial (people prepare specifically for them rather than building resilience by default)",pos:0.5}],
     sizes_cfg:{
       large:{range:"Monthly chaos in staging + quarterly game days in production",rec:"Start simple and escalate: (1) Week 1: Kill one instance of your most critical service in staging. Does the load balancer remove it within 30 seconds? Does a new instance start within 2 minutes? Does traffic shift seamlessly? If not, fix the fundamentals before doing anything fancier. (2) Week 2: Inject 500ms latency between service A and its database. Do circuit breakers trip? Does the service return a fallback? Does it recover when latency returns to normal? (3) Week 3: Simulate a full AZ failure in staging (kill all instances in one AZ). Does traffic redistribute? Does the system stay within SLO? (4) Month 2+: Move to production — start with a single non-critical instance kill during business hours with the team watching. Build confidence gradually. Technologies: Gremlin ($80/host/month for 50+ hosts — the safest way to start because it provides guardrails: automatic abort if error rate exceeds a threshold, predefined experiment types, great documentation). Chaos Mesh (free, open source, CNCF project, Kubernetes-native — excellent if you're on K8s; inject pod kills, network delays, disk failures, CPU stress via CRDs). AWS FIS (free tool, integrates with CloudWatch for abort conditions — good for AWS-native shops). Chaos Monkey (Netflix's original, kills random instances — simple but no guardrails; best for teams that already have mature monitoring).",tools:["Gremlin","Chaos Mesh","AWS FIS","Chaos Monkey"]},
       hyper:{range:"Continuous chaos in production + automated game days",rec:"Always-on low-rate chaos: configure your service mesh (Istio/Envoy) to inject failures continuously at a low rate — 0.01% of requests between any two services get a 100ms delay, 0.001% get a 503 error. This ensures that circuit breakers, retries, and fallbacks are exercised constantly, not just during drills. The rate is low enough that user impact is negligible (your error budget can absorb it) but high enough to keep resilience mechanisms warm. Weekly major experiments: rotate through failure scenarios each week — AZ failure, dependency timeout cascade, cache failure, DNS resolution failure, certificate expiration. Quarterly game days: simulate multi-failure scenarios with cross-team participation (e.g., 'AZ failure + 3× traffic spike + primary database failover' simultaneously). Document findings, remediate gaps, and track MTTD/MTTR trends over time. Technologies: custom chaos platform (many hyper-scale companies build their own because they need integration with their specific deployment, monitoring, and rollback systems), Gremlin Enterprise (managed, supports complex multi-step scenarios, team management features), AWS FIS at scale (inject failures across multiple services/accounts simultaneously, integrated with CloudWatch for automatic abort).",tools:["Custom chaos platform","Gremlin Enterprise","AWS FIS at scale","Istio fault injection"]}
     },
     levelUp:[
       {from:"large",to:"hyper",trigger:"Monthly drills feel artificial (teams prepare specifically and revert changes after), or a real outage reveals a failure mode that chaos drills never tested",action:"Move from scheduled drills to continuous always-on chaos. Configure your service mesh to inject low-rate failures permanently (0.01% latency injection, 0.001% error injection). This keeps resilience mechanisms continuously exercised — circuit breakers that only trip during monthly drills may have configuration drift; always-on chaos catches this. Implement automated game days: a platform that randomly selects a failure scenario from a library, executes it, measures MTTD/MTTR, and generates a report — no human scheduling required. Start with the simplest scenario (single instance kill) always-on, and add more complex scenarios (AZ failure, cascading timeout) monthly."}
     ],
     examples:[
       {name:"Netflix Chaos Monkey — the origin story",desc:"In 2010, after moving to AWS, Netflix realized that AWS instances could fail at any time. Rather than hoping it wouldn't happen, they built Chaos Monkey to randomly kill EC2 instances during business hours. Engineers who deployed services that couldn't survive an instance kill got woken up by pager alerts. Rapidly, every Netflix service was designed to handle instance failures gracefully. The result: Netflix routinely survives AWS outages that take down half the internet. When us-east-1 had a major outage in 2017, Netflix was one of the few major services that stayed online. Chaos engineering didn't just improve their resilience — it made resilience a cultural value."},
       {name:"AWS GameDay — practicing for the real thing",desc:"AWS runs annual GameDay exercises where engineering teams simulate region-level failures. Teams practice their failover procedures before they need them for real. The exercises have consistently revealed gaps: runbooks with outdated steps, IAM roles that don't work cross-region, DNS TTLs that are too long for fast failover. Finding these gaps during a drill costs hours; finding them during a real outage costs days and millions. GameDay has become an industry term — many companies now run their own."},
       {name:"Slack's 2022 incident and chaos lessons",desc:"Slack experienced a significant outage traced to a database migration that interacted poorly with their connection pooling under load. Their subsequent postmortem noted that their chaos experiments hadn't covered the specific interaction between schema changes and connection pool behavior under high connection churn. They expanded their chaos experiments to include database-layer failures (connection pool exhaustion, replication lag spikes, lock contention) — demonstrating that chaos engineering is not a checkbox but a continuously expanding practice that evolves with your system's failure modes."}
     ],
     related:[{id:"reliability",label:"Reliability & DR"},{id:"rel-cb",label:"Circuit Breakers"}],
     children:[]},

    {name:"Contract Testing",id:"test-contract",icon:"🤝",phase:"Testing",color:"#fb923c",
     sizes:["medium","large","hyper"],short:"Producer/consumer-driven contracts — the most cost-effective test in microservices",
     detail:{
       what:"Contract testing verifies that the API contract between two services — the request/response shape, status codes, headers, and field types — hasn't been broken by a change in either service. Unlike integration tests (which require both services running together), contract tests run independently: the consumer defines what it expects from the producer (a 'contract'), and the producer verifies it can fulfill that contract without needing the consumer to be present. If a producer change would break a consumer's contract, the producer's CI fails — preventing the breaking change from being deployed. This catches the single most common microservices bug: a producer team changes an API (renames a field, removes a response field, changes a type) without realizing a consumer depends on it. The change passes all of the producer's own tests (because the producer's tests don't know about the consumer's expectations), gets deployed, and breaks the consumer in production. Contract tests close this gap. For event-driven systems, schema registries (Confluent Schema Registry for Avro, Buf for Protobuf) serve a similar purpose: they enforce that event schema changes are backward-compatible, preventing producers from publishing events that consumers can't parse.",
       why:"In a microservices architecture, end-to-end tests that spin up all services and test user journeys are the intuitive answer to 'how do I verify everything works together?' But at scale, E2E tests are a trap: they're slow (spin up 10+ services, each with its own database), flaky (network timing, service startup order, test data setup failures), hard to debug (which of 10 services caused the failure?), and create coupling (a change in any service can break any E2E test). Google research showed that >50% of E2E test failures are due to infrastructure issues, not actual bugs. Contract tests provide 80–90% of the value of E2E tests at ~1% of the cost: they verify the critical thing (do services agree on the interface?) without the expensive thing (running everything together). Pact-style contract tests run in <5 seconds per service boundary. An E2E test covering the same flow takes 5–15 minutes. For a system with 50 service boundaries, that's 4 minutes of contract testing vs 4+ hours of E2E. The ROI is overwhelming.",
       numbers:"Contract tests run 5–10× faster than equivalent E2E tests. They catch the most common microservices failure mode (incompatible API change deployed independently) with near-100% accuracy. False positive rate: <1% (compared to 10–30% for E2E tests, primarily from infrastructure flakiness). Coverage model: write a contract test for every consumer→producer dependency. A system with 30 services and 50 inter-service dependencies needs ~50 contract test pairs — each taking 1–2 hours to write initially. Schema registry checking: instant (happens at schema registration time, not test time). Pact broker (Pactflow) cost: $99/month for teams, $399/month for enterprise. Buf schema registry: free for open source, $40/user/month for managed."
     },
     tradeoffs:[{axis:"Coverage vs Coupling",left:"Consumer-driven contracts (Pact-style): consumer explicitly defines expectations, producer verifies — strongest coverage of what consumers actually need, but creates a coupling where producers must know about consumer expectations",right:"Schema-level compatibility (registry): producer defines the schema, registry checks backward/forward compatibility automatically — less coupled but doesn't verify semantic behavior (e.g., 'field X should never be null for active users')",pos:0.6},{axis:"Strictness vs Flexibility",left:"Strict contracts: any field change requires consumer contract update — safe but slows producers who want to evolve their API",right:"Loose contracts (only check fields consumers actually use, ignore extras): more flexible but may miss breaking changes in fields the contract doesn't cover",pos:0.5}],
     sizes_cfg:{
       medium:{range:"Pact contracts between key services, schema registry for events",rec:"Start with Pact for your 3–5 most critical service-to-service HTTP dependencies. Pact workflow: (1) Consumer team writes a 'pact' — a test that specifies 'when I call GET /users/123, I expect a JSON body with fields {id: integer, name: string, email: string}.' (2) The pact is published to a Pact Broker (Pactflow SaaS or self-hosted). (3) Producer's CI fetches consumer pacts and verifies: 'can my service produce responses matching all consumer expectations?' (4) If verification fails, the producer's deploy is blocked. For event schemas: use Confluent Schema Registry (if using Kafka + Avro — enforces backward/forward compatibility on every schema registration, preventing producers from publishing events consumers can't parse) or Buf (for Protobuf — lints and checks compatibility of .proto files in CI). Technologies: Pact (open source, supports 10+ languages including JS, Java, Python, Go, Ruby — the industry standard for consumer-driven contract testing), Pactflow (managed Pact broker, $99/month — adds a web UI, can-i-deploy checks, and webhook notifications), Buf (Protobuf schema management — linting, breaking change detection, code generation — $40/user/month for managed, free for open source), Confluent Schema Registry (free with Confluent Platform or $0.005/schema per month on Confluent Cloud).",tools:["Pact","Pactflow","Buf","Confluent Schema Registry"]},
       large:{range:"Centralized contract registry + CI gate on every service deploy",rec:"Mandate contract tests on every inter-service dependency — no exceptions. A service cannot deploy if it breaks any consumer's contract. This is enforced by the CI pipeline: `pact verify` or `buf breaking` must pass before the deploy pipeline proceeds. Centralized contract registry (Pactflow or custom) serves as the single source of truth for all inter-service contracts. Add 'can-i-deploy' checks: before deploying a new version, query the broker to verify that this version's contracts are satisfied by all current production versions of its dependencies (and vice versa). For event schemas: forward + backward compatibility checking in CI — every schema change must be parseable by the previous consumer version (backward) and the current consumer version (forward). Technologies: Pactflow (managed, adds 'can-i-deploy' matrix — the killer feature that answers 'is it safe to deploy this version right now?' based on the current state of all contracts), Buf with CI integration (checks .proto files for breaking changes on every PR), Apicurio Registry (open source schema registry supporting Avro, Protobuf, JSON Schema — good alternative to Confluent's).",tools:["Pactflow","Buf","Apicurio","CI contract gates"]},
       hyper:{range:"Auto-generated SDKs from schemas + automated compatibility evolution",rec:"At hyper-scale, manually writing contracts becomes unsustainable across 500+ services. Instead: auto-generate client SDKs from schema definitions (Protobuf → generated client libraries in every language using Buf or custom code generators, OpenAPI → generated clients using openapi-generator). The schema IS the contract — any breaking change to the schema is caught by automated compatibility checks before it's even committed. For breaking changes that are genuinely necessary: use a blue/green contract migration pattern — deploy the new producer version alongside the old, shift consumers one at a time, retire the old version when all consumers have migrated. Technologies: Buf (auto-generated clients from Protobuf with breaking change detection — the modern gold standard), custom SDK generation pipelines (many hyper-scale companies auto-generate SDKs in CI and publish them as internal packages), schema compatibility bots (automated PRs that update consumer SDKs when a producer schema changes in a compatible way).",tools:["Buf","custom SDK generation","schema compatibility bots","openapi-generator"]}
     },
     levelUp:[
       {from:"medium",to:"large",trigger:"A breaking API change deployed independently causes a production incident, or >20 inter-service dependencies make manual contract management error-prone",action:"Mandate contract tests on all service boundaries. Deploy Pactflow ($99–$399/month) as your contract broker. Add 'can-i-deploy' checks to every service's CI pipeline: before deploying, the pipeline queries Pactflow to verify this version is compatible with all production dependencies. Integrate Buf for Protobuf schemas in CI — every PR that modifies a .proto file gets automatic breaking change detection. This takes 1–2 weeks to roll out across existing services and prevents the most common microservices failure mode going forward."},
       {from:"large",to:"hyper",trigger:"Maintaining contracts manually across 500+ services is unsustainable, or SDK versioning across consumers is causing deployment coordination overhead",action:"Move to auto-generated SDKs from schemas. Build a CI pipeline that: (1) detects schema changes in a producer's PR, (2) runs compatibility checks against all consumer contracts, (3) auto-generates updated client libraries, (4) opens PRs in consumer repos with the updated SDK. This eliminates the human coordination overhead of contract management. Deploy a schema governance team (or automated bot) that reviews and approves schema changes for backward/forward compatibility. This takes 2–3 months to build but transforms cross-service coordination from a human process to an automated one."}
     ],
     related:[{id:"api-proto",label:"Protocol Selection"},{id:"api",label:"API Design"}],
     children:[]}
  ]
};
